// mm/src/steps/UploadStep.js
import React, { useRef, useState } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { uploadFile } from '../api/upload';
import { useWorkflow } from '../store/workflowContext';

const UploadStep = () => {
  const { manuscriptFiles, addFile, setPreviewText } = useWorkflow();
  const [progress, setProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const fileRef = useRef(null);

  const handleFiles = async (files) => {
    if (!files || files.length === 0) return;
    const file = files[0];

    // Read local text so Preview can show real manuscript pages
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = String(e.target?.result || '');
      // Limit to first 200k chars for performance (optional)
      setPreviewText(text.slice(0, 200000));
    };
    // This works well for .txt / .md; for Word/PDF you'd need a server parser later
    reader.readAsText(file);

    const id = uuidv4();
    const baseMeta = {
      id,
      name: file.name,
      size: file.size,
    };

    // Optimistically show "uploading" file
    addFile({
      ...baseMeta,
      status: 'uploading',
      progress: 0,
    });

    setIsUploading(true);
    try {
      const resp = await uploadFile(file, (pct) => {
        setProgress(pct);
        // you could also update progress in the store if desired
      });

      addFile({
        ...baseMeta,
        status: 'done',
        progress: 100,
        serverResponse: resp.data,
      });
      setProgress(100);
    } catch (err) {
      console.error('Upload failed', err);
      addFile({
        ...baseMeta,
        status: 'error',
        progress: 0,
      });
    } finally {
      setIsUploading(false);
    }
  };

  const onDrop = (e) => {
    e.preventDefault();
    const dt = e.dataTransfer;
    handleFiles(dt.files);
  };

  const onChoose = (e) => {
    handleFiles(e.target.files);
  };

  return (
    <div>
      <div className="border-2 border-dashed border-slate-200 rounded-xl p-8 flex flex-col items-center">
        <div className="mb-4 text-slate-700">
          <h3 className="text-2xl font-semibold">Upload Your Book Files</h3>
          <p className="text-sm text-slate-500">
            PDF, DOCX, TXT, MD — up to 50MB
          </p>
        </div>

        <div
          onDrop={onDrop}
          onDragOver={(e) => e.preventDefault()}
          className="w-full py-12 flex items-center justify-center rounded-lg bg-gradient-to-br from-slate-50 to-white"
        >
          <div className="text-center">
            <input
              ref={fileRef}
              type="file"
              onChange={onChoose}
              className="hidden"
            />
            <button
              onClick={() => fileRef.current && fileRef.current.click()}
              className="px-6 py-3 bg-blue-600 text-white rounded-md shadow"
            >
              Upload a file
            </button>
            <div className="mt-4 text-sm text-slate-500">
              or drag and drop here
            </div>
          </div>
        </div>

        <div className="mt-6 w-full">
          {isUploading && (
            <div className="w-full bg-slate-100 rounded overflow-hidden mb-3">
              <div
                style={{ width: `${progress}%` }}
                className="h-2 bg-blue-600 transition-all"
              />
              <div className="text-sm text-slate-600 mt-2">
                Uploading: {progress}%
              </div>
            </div>
          )}

          <div className="mt-2">
            <h4 className="text-sm font-medium text-slate-700">Files</h4>
            <ul className="mt-2 space-y-2">
              {manuscriptFiles.map((f) => (
                <li
                  key={f.id}
                  className="flex items-center justify-between border rounded p-2"
                >
                  <div>
                    <div className="font-medium">{f.name}</div>
                    <div className="text-xs text-slate-500">
                      {f.status || 'ready'}
                    </div>
                  </div>
                  <div className="text-sm text-slate-500">
                    {Math.round((f.size || 0) / 1024)} KB
                  </div>
                </li>
              ))}
            </ul>
          </div>
        </div>
      </div>

      <div className="mt-6 flex justify-end">
        {/* Continue button is controlled in WorkflowContainer; no button here */}
      </div>
    </div>
  );
};

export default UploadStep;
